//! ocr-server — sovereign IMAGE→TEXT (OCR) endpoint (non-token serving contract).
//!
//! The REAL GLM-OCR read, wrapped as a minimal HTTP service. Image bytes in,
//! extracted text out. Same pipeline as `bin/ocr-probe.rs` (GLM-OCR ViT →
//! splice into the qwen2-stamped text backbone → greedy decode → detokenize),
//! but with the Qwen2.5-VL preprocessing ported to native Rust (no python) so
//! the server is self-contained.
//!
//!   GET  /healthz   -> {"ok":true,"hidden":N,"layers":N,"visual_tokens":256}
//!   POST /ocr       body = raw image bytes (png/jpeg/webp) -> {"text":"..."}
//!
//! WEIGHTS: a REAL dense `.knot` (GLM-OCR text backbone + vision tower) encoded
//! by encode-knot.py's glm_ocr branch, plus a tokenizer GGUF (tokenizer.ggml.tokens).
//!
//!   cargo run --release --bin ocr-server -- \
//!     --knot ~/.edgework/models/glm-ocr.knot \
//!     --tokenizer /path/glm-ocr-tokenizer.gguf [--port 8091]

use std::sync::{Arc, Mutex};
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model::NativeLlamaPipeline;
use distributed_inference::model_glm_ocr_vit::{GlmOcrViT, GlmOcrVitConfig};
use image::imageops::FilterType;
use tiny_http::{Header, Method, Response, Server};

// Qwen2.5-VL / GLM-OCR CLIP normalization (matches preprocess-vl-image.py).
const IMAGE_MEAN: [f32; 3] = [0.48145466, 0.4578275, 0.40821073];
const IMAGE_STD: [f32; 3] = [0.26862954, 0.261_302_6, 0.275_777_1];
const PATCH: usize = 14;
const TEMPORAL: usize = 2;
const IN_CHANS: usize = 3;
const SIDE: usize = 448; // target side (multiple of PATCH*MERGE=28)
const GRID: usize = SIDE / PATCH; // 32
const N_VISUAL: usize = (GRID / 2) * (GRID / 2); // 256 merged visual tokens
const PATCH_DIM: usize = IN_CHANS * TEMPORAL * PATCH * PATCH; // 1176
const GLM_IMAGE_PAD: u32 = 59280;

fn die(msg: impl AsRef<str>) -> ! {
    eprintln!("ocr-server: {}", msg.as_ref());
    std::process::exit(2);
}

fn arg(flag: &str, default: &str) -> String {
    let a: Vec<String> = std::env::args().collect();
    a.iter()
        .position(|x| x == flag)
        .and_then(|i| a.get(i + 1).cloned())
        .unwrap_or_else(|| default.to_string())
}

/// Build the GLM-OCR chat prompt token IDs: [gMASK]<sop><|user|>\n
/// <|begin_of_image|> {N_VISUAL × <|image|>} <|end_of_image|>
/// "Read all the text in this image." <|assistant|>\n
/// The image-pad span (59280) is overwritten by ViT tokens at runtime.
fn build_prompt_tokens() -> (Vec<u32>, usize) {
    let mut t: Vec<u32> = vec![59248, 59250, 59253, 10, 59256]; // gMASK,sop,user,\n,begin_of_image
    let img_start = t.len();
    t.extend(std::iter::repeat_n(GLM_IMAGE_PAD, N_VISUAL));
    // end_of_image, "Read all the text in this image.", assistant, \n
    t.extend_from_slice(&[59257, 6872, 873, 283, 2815, 309, 643, 5155, 46, 59254, 10]);
    (t, img_start)
}

/// Decode + CLIP-normalize + tile an image into [GRID*GRID, PATCH_DIM] patch rows,
/// in Conv3d weight order [in_chan, temporal, py, px] (matches preprocess-vl-image.py).
fn preprocess(bytes: &[u8]) -> Result<Vec<f32>, String> {
    let img = image::load_from_memory(bytes)
        .map_err(|e| format!("decode image: {e}"))?
        .resize_exact(SIDE as u32, SIDE as u32, FilterType::Lanczos3)
        .to_rgb8();
    // CHW normalized.
    let mut chw = vec![0f32; IN_CHANS * SIDE * SIDE];
    for y in 0..SIDE {
        for x in 0..SIDE {
            let px = img.get_pixel(x as u32, y as u32);
            for c in 0..IN_CHANS {
                let v = px[c] as f32 / 255.0;
                chw[c * SIDE * SIDE + y * SIDE + x] = (v - IMAGE_MEAN[c]) / IMAGE_STD[c];
            }
        }
    }
    let mut out = vec![0f32; GRID * GRID * PATCH_DIM];
    for py in 0..GRID {
        for px in 0..GRID {
            let p = py * GRID + px;
            let mut off = 0usize;
            for c in 0..IN_CHANS {
                for _t in 0..TEMPORAL {
                    for iy in 0..PATCH {
                        for ix in 0..PATCH {
                            let yy = py * PATCH + iy;
                            let xx = px * PATCH + ix;
                            out[p * PATCH_DIM + off] = chw[c * SIDE * SIDE + yy * SIDE + xx];
                            off += 1;
                        }
                    }
                }
            }
        }
    }
    Ok(out)
}

/// GPT-2 byte-level decode of GGUF tokenizer tokens (copied from ocr-probe.rs).
fn gpt2_byte_decode(tokens: &[String], ids: &[u32]) -> String {
    let mut byte_decoder = std::collections::HashMap::new();
    let mut printable: Vec<u32> = Vec::new();
    for r in (b'!' as u32)..=(b'~' as u32) {
        printable.push(r);
    }
    for r in 0xA1u32..=0xAC {
        printable.push(r);
    }
    for r in 0xAEu32..=0xFF {
        printable.push(r);
    }
    let mut extra = 0u32;
    let mut mapping: Vec<(u32, char)> = Vec::new();
    for b in 0u32..256 {
        if printable.contains(&b) {
            mapping.push((b, char::from_u32(b).unwrap()));
        } else {
            let c = char::from_u32(256 + extra).unwrap();
            mapping.push((b, c));
            extra += 1;
        }
    }
    for (b, c) in mapping {
        byte_decoder.insert(c, b as u8);
    }
    let mut out_bytes: Vec<u8> = Vec::new();
    for &id in ids {
        let Some(tok) = tokens.get(id as usize) else {
            continue;
        };
        for ch in tok.chars() {
            if let Some(&b) = byte_decoder.get(&ch) {
                out_bytes.push(b);
            } else {
                let mut buf = [0u8; 4];
                out_bytes.extend_from_slice(ch.encode_utf8(&mut buf).as_bytes());
            }
        }
    }
    String::from_utf8_lossy(&out_bytes).into_owned()
}

/// Walk a GGUF and return `tokenizer.ggml.tokens` (copied from ocr-probe.rs).
fn read_gguf_tokens(path: &std::path::Path) -> Result<Vec<String>, String> {
    use std::io::{Read, Seek, SeekFrom};
    const GGUF_MAGIC: u32 = 0x4655_4747;
    const T_STRING: u32 = 8;
    const T_ARRAY: u32 = 9;
    let mut f = std::fs::File::open(path).map_err(|e| format!("open gguf: {e}"))?;
    fn rd_u32(f: &mut std::fs::File) -> Result<u32, String> {
        let mut b = [0u8; 4];
        f.read_exact(&mut b).map_err(|e| e.to_string())?;
        Ok(u32::from_le_bytes(b))
    }
    fn rd_u64(f: &mut std::fs::File) -> Result<u64, String> {
        let mut b = [0u8; 8];
        f.read_exact(&mut b).map_err(|e| e.to_string())?;
        Ok(u64::from_le_bytes(b))
    }
    fn rd_string(f: &mut std::fs::File) -> Result<String, String> {
        let len = rd_u64(f)? as usize;
        let mut buf = vec![0u8; len];
        f.read_exact(&mut buf).map_err(|e| e.to_string())?;
        Ok(String::from_utf8_lossy(&buf).into_owned())
    }
    fn scalar_size(t: u32) -> Result<u64, String> {
        Ok(match t {
            0 | 1 | 7 => 1,
            2 | 3 => 2,
            4..=6 => 4,
            10..=12 => 8,
            other => return Err(format!("unsupported gguf scalar type {other}")),
        })
    }
    fn skip_value(f: &mut std::fs::File, t: u32) -> Result<(), String> {
        match t {
            T_STRING => {
                let len = rd_u64(f)?;
                f.seek(SeekFrom::Current(len as i64)).map_err(|e| e.to_string())?;
            }
            T_ARRAY => {
                let at = rd_u32(f)?;
                let al = rd_u64(f)?;
                if at == T_STRING {
                    for _ in 0..al {
                        let len = rd_u64(f)?;
                        f.seek(SeekFrom::Current(len as i64)).map_err(|e| e.to_string())?;
                    }
                } else {
                    let sz = scalar_size(at)?;
                    f.seek(SeekFrom::Current((sz * al) as i64)).map_err(|e| e.to_string())?;
                }
            }
            scalar => {
                let sz = scalar_size(scalar)?;
                f.seek(SeekFrom::Current(sz as i64)).map_err(|e| e.to_string())?;
            }
        }
        Ok(())
    }
    if rd_u32(&mut f)? != GGUF_MAGIC {
        return Err("not a GGUF file (bad magic)".to_string());
    }
    let version = rd_u32(&mut f)?;
    if version < 2 {
        return Err(format!("unsupported GGUF version {version}"));
    }
    let _n_tensors = rd_u64(&mut f)?;
    let n_kv = rd_u64(&mut f)?;
    for _ in 0..n_kv {
        let key = rd_string(&mut f)?;
        let vtype = rd_u32(&mut f)?;
        if key == "tokenizer.ggml.tokens" {
            if vtype != T_ARRAY {
                return Err("tokenizer.ggml.tokens is not an array".to_string());
            }
            let at = rd_u32(&mut f)?;
            if at != T_STRING {
                return Err("tokenizer.ggml.tokens is not a string array".to_string());
            }
            let al = rd_u64(&mut f)? as usize;
            let mut tokens = Vec::with_capacity(al);
            for _ in 0..al {
                tokens.push(rd_string(&mut f)?);
            }
            return Ok(tokens);
        }
        skip_value(&mut f, vtype)?;
    }
    Err("GGUF metadata has no tokenizer.ggml.tokens".to_string())
}

fn argmax(v: &[f32]) -> usize {
    v.iter()
        .enumerate()
        .fold((0usize, f32::NEG_INFINITY), |(bi, bv), (i, &x)| {
            if x > bv {
                (i, x)
            } else {
                (bi, bv)
            }
        })
        .0
}

struct OcrEngine {
    pipeline: NativeLlamaPipeline,
    vit: GlmOcrViT,
    tokens: Vec<String>,
    prompt: Vec<u32>,
    img_start: usize,
    hidden_dim: usize,
    num_layers: usize,
    max_new: usize,
}

impl OcrEngine {
    /// Run the full REAL OCR read on one image's preprocessed patches.
    fn read(&mut self, pixels: &[f32]) -> Result<String, String> {
        let hidden_dim = self.hidden_dim;
        let num_layers = self.num_layers;
        self.pipeline.reset_context_and_kv();

        // ViT → visual tokens [N_VISUAL, hidden].
        let visual = self.vit.forward(pixels, GRID, GRID).map_err(|e| format!("ViT: {e}"))?;
        let n_visual = visual.len() / hidden_dim;
        if n_visual != N_VISUAL {
            return Err(format!("ViT produced {n_visual} tokens, expected {N_VISUAL}"));
        }

        // Embed prompt + splice visual tokens over the <|image|> placeholder span.
        let mut residual = self
            .pipeline
            .embed_chunk(&self.prompt, 0)
            .map_err(|e| format!("embed: {e}"))?;
        residual[self.img_start * hidden_dim..(self.img_start + n_visual) * hidden_dim]
            .copy_from_slice(&visual);
        let seq_len = self.prompt.len();

        // Chunked prefill.
        const PREFILL_CHUNK: usize = 8;
        let mut last_out: Vec<f32> = Vec::new();
        let mut last_len = 0usize;
        let mut chunk_start = 0usize;
        while chunk_start < seq_len {
            let chunk_len = (seq_len - chunk_start).min(PREFILL_CHUNK);
            let chunk_in =
                &residual[chunk_start * hidden_dim..(chunk_start + chunk_len) * hidden_dim];
            for layer in 0..num_layers {
                let is_first = layer == 0;
                let is_last = layer == num_layers - 1;
                let attn_in: &[f32] = if is_first { chunk_in } else { &[] };
                self.pipeline
                    .forward_range_attn_chunk(attn_in, layer, chunk_start, chunk_len, is_first)
                    .map_err(|e| format!("attn L{layer}: {e}"))?;
                self.pipeline
                    .forward_range_ffn_gate_chunk(layer, chunk_len)
                    .map_err(|e| format!("ffn_gate L{layer}: {e}"))?;
                self.pipeline
                    .forward_range_ffn_up_chunk(layer, chunk_len)
                    .map_err(|e| format!("ffn_up L{layer}: {e}"))?;
                let out = self
                    .pipeline
                    .forward_range_ffn_down_chunk(layer, chunk_len, is_last)
                    .map_err(|e| format!("ffn_down L{layer}: {e}"))?;
                if is_last {
                    last_out = out;
                    last_len = chunk_len;
                }
            }
            chunk_start += chunk_len;
        }

        let logits = self
            .pipeline
            .lm_head_only(&last_out, last_len)
            .map_err(|e| format!("lm_head: {e}"))?;
        let first_tok = argmax(&logits) as u32;

        // Greedy decode. EOS ids 59246 (pad/eos) and 59253 (<|user|>).
        let stop = |t: u32| t == 59246 || t == 59253;
        let mut generated: Vec<u32> = vec![first_tok];
        let mut cur = first_tok;
        let mut pos = seq_len;
        for _ in 1..self.max_new {
            if stop(cur) {
                break;
            }
            let (next, _, _) = self
                .pipeline
                .decode_next_fast_argmax(cur, pos)
                .map_err(|e| format!("decode @{pos}: {e}"))?;
            pos += 1;
            generated.push(next);
            cur = next;
        }
        let kept: Vec<u32> = generated.into_iter().filter(|t| !stop(*t)).collect();
        Ok(gpt2_byte_decode(&self.tokens, &kept).trim().to_string())
    }
}

fn json_escape(s: &str) -> String {
    let mut o = String::with_capacity(s.len() + 2);
    for c in s.chars() {
        match c {
            '"' => o.push_str("\\\""),
            '\\' => o.push_str("\\\\"),
            '\n' => o.push_str("\\n"),
            '\r' => o.push_str("\\r"),
            '\t' => o.push_str("\\t"),
            c if (c as u32) < 0x20 => o.push_str(&format!("\\u{:04x}", c as u32)),
            c => o.push(c),
        }
    }
    o
}

fn main() {
    let knot_path = arg("--knot", "/Users/buley/.edgework/models/glm-ocr.knot");
    let tok_path = arg("--tokenizer", "");
    let port: u16 = arg("--port", "8091").parse().unwrap_or(8091);
    let max_new: usize = arg("--max-new", "64").parse().unwrap_or(64);

    eprintln!("ocr-server: loading knot {knot_path}");
    let t0 = Instant::now();
    let knot = KnotWeights::load(&knot_path).unwrap_or_else(|e| die(format!("knot load: {e}")));
    let cfg = knot.config.clone().unwrap_or_else(|| die("knot has no config"));
    let hidden_dim = cfg.hidden_dim;
    let num_layers = cfg.num_layers;
    let backend = Arc::clone(&knot.backend);
    if !backend.has_tensor("vit_patch_embed_weight") {
        die("knot has no vit_patch_embed_weight — re-encode with encode-knot.py glm_ocr branch");
    }
    let vit = GlmOcrViT::new(GlmOcrVitConfig::default(), backend);
    let pipeline = NativeLlamaPipeline::from_knot(knot, false, 0.0);

    let tokens = if tok_path.is_empty() {
        eprintln!("ocr-server: WARNING no --tokenizer; /ocr will return token-id text only");
        Vec::new()
    } else {
        read_gguf_tokens(std::path::Path::new(&tok_path))
            .unwrap_or_else(|e| die(format!("tokenizer: {e}")))
    };
    let (prompt, img_start) = build_prompt_tokens();
    eprintln!(
        "ocr-server: ready in {:.1}s  hidden={hidden_dim} layers={num_layers} visual_tokens={N_VISUAL} vocab_tokens={}",
        t0.elapsed().as_secs_f32(),
        tokens.len()
    );

    let engine = Arc::new(Mutex::new(OcrEngine {
        pipeline,
        vit,
        tokens,
        prompt,
        img_start,
        hidden_dim,
        num_layers,
        max_new,
    }));

    let server = Server::http(("0.0.0.0", port))
        .unwrap_or_else(|e| die(format!("bind :{port}: {e}")));
    eprintln!("ocr-server: listening on http://0.0.0.0:{port}  (GET /healthz, POST /ocr)");

    let json = |code: u32, body: String| {
        Response::from_string(body).with_status_code(code).with_header(
            Header::from_bytes(&b"Content-Type"[..], &b"application/json"[..]).unwrap(),
        )
    };

    for mut req in server.incoming_requests() {
        let url = req.url().to_string();
        let method = req.method().clone();
        let path = url.split('?').next().unwrap_or("/");
        match (&method, path) {
            (Method::Get, "/healthz") => {
                let body = format!(
                    "{{\"ok\":true,\"hidden\":{hidden_dim},\"layers\":{num_layers},\"visual_tokens\":{N_VISUAL}}}"
                );
                let _ = req.respond(json(200, body));
            }
            (Method::Post, "/ocr") => {
                let mut buf = Vec::new();
                if let Err(e) = req.as_reader().read_to_end(&mut buf) {
                    let _ = req.respond(json(400, format!("{{\"error\":\"read body: {e}\"}}")));
                    continue;
                }
                if buf.is_empty() {
                    let _ = req.respond(json(400, "{\"error\":\"empty body\"}".to_string()));
                    continue;
                }
                let t = Instant::now();
                let result = match preprocess(&buf) {
                    Ok(pixels) => {
                        let mut eng = engine.lock().unwrap();
                        eng.read(&pixels)
                    }
                    Err(e) => Err(e),
                };
                match result {
                    Ok(text) => {
                        eprintln!("  /ocr {}B -> {:?}  ({:.1}s)", buf.len(), text, t.elapsed().as_secs_f32());
                        let body = format!(
                            "{{\"text\":\"{}\",\"ms\":{}}}",
                            json_escape(&text),
                            t.elapsed().as_millis()
                        );
                        let _ = req.respond(json(200, body));
                    }
                    Err(e) => {
                        let _ = req.respond(json(500, format!("{{\"error\":\"{}\"}}", json_escape(&e))));
                    }
                }
            }
            _ => {
                let _ = req.respond(json(404, "{\"error\":\"not found\"}".to_string()));
            }
        }
    }
}
